import{_ as d,o as e,c as a,ag as r}from"./chunks/framework.DwAt1PVX.js";const u=JSON.parse('{"title":"03 · QtWidgets 传统界面（进阶）","description":"深入 QtWidgets 的布局策略、事件分发机制、Model/View 架构、QSS 主题系统、自定义绘制、主窗口管理等高级主题，以及 60+ 控件的高级 API 与工程实践。","frontmatter":{"title":"03 · QtWidgets 传统界面（进阶）","description":"深入 QtWidgets 的布局策略、事件分发机制、Model/View 架构、QSS 主题系统、自定义绘制、主窗口管理等高级主题，以及 60+ 控件的高级 API 与工程实践。"},"headers":[],"relativePath":"advanced/03-qtwidgets/index.md","filePath":"advanced/03-qtwidgets/index.md","lastUpdated":null}'),i={name:"advanced/03-qtwidgets/index.md"};function o(l,t,s,n,h,c){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="_03-·-qtwidgets-传统界面-进阶" tabindex="-1">03 · QtWidgets 传统界面（进阶） <a class="header-anchor" href="#_03-·-qtwidgets-传统界面-进阶" aria-label="Permalink to &quot;03 · QtWidgets 传统界面（进阶）&quot;">​</a></h1><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>本模块是 QtWidgets 的进阶教程，分为两大篇章：</p><p><strong>主题能力篇（01-10）</strong> 涵盖布局系统深挖、事件分发链、Model/View 架构、QSS 动态主题、自定义控件 QStyle 绘制、对话框模态策略、主窗口持久化、图形视图框架、动画状态机、MDI 多文档界面等核心主题。每一篇都在入门基础上深入原理、高级 API 和工程实践。</p><p><strong>控件速查篇（11-74）</strong> 与入门层一一对应，每个控件独立成篇，聚焦高级 API 用法、性能陷阱、自定义扩展和工程实践，不再重复入门层已覆盖的基础用法。</p><h2 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h2><ul><li>已完成入门层 03-QtWidgets 全部章节</li><li>熟悉 C++17 基础、Qt 对象系统和信号槽机制</li><li>了解进阶篇 01-QtBase、02-QtGui 的核心内容</li></ul><h2 id="章节目录" tabindex="-1">章节目录 <a class="header-anchor" href="#章节目录" aria-label="Permalink to &quot;章节目录&quot;">​</a></h2><h3 id="主题能力篇" tabindex="-1">主题能力篇 <a class="header-anchor" href="#主题能力篇" aria-label="Permalink to &quot;主题能力篇&quot;">​</a></h3><table tabindex="0"><thead><tr><th>章节</th><th>标题</th><th>核心内容</th></tr></thead><tbody><tr><td>3.1</td><td>布局系统进阶</td><td>QSizePolicy 策略、动态布局切换、嵌套布局性能</td></tr><tr><td>3.2</td><td>事件处理进阶</td><td>输入捕获、原生事件、事件传播链截断</td></tr><tr><td>3.3</td><td>Model/View 进阶</td><td>自定义 Model、代理模型、自定义 Delegate</td></tr><tr><td>3.4</td><td>QSS 进阶</td><td>动态主题、复杂选择器、qproperty 属性注入</td></tr><tr><td>3.5</td><td>自定义控件进阶</td><td>QStyle 绘制、子控件矩形、Designer 插件</td></tr><tr><td>3.6</td><td>对话框进阶</td><td>模态策略、数据验证、多步向导</td></tr><tr><td>3.7</td><td>主窗口进阶</td><td>Dock 管理、状态持久化、角落区域归属</td></tr><tr><td>3.8</td><td>图形视图进阶</td><td>自定义 Item、碰撞检测、效果系统</td></tr><tr><td>3.9</td><td>动画进阶</td><td>状态机驱动、并行动画组、自定义插值</td></tr><tr><td>3.10</td><td>MDI 进阶</td><td>子窗口管理、菜单同步、场景选择</td></tr></tbody></table><h3 id="控件速查篇" tabindex="-1">控件速查篇 <a class="header-anchor" href="#控件速查篇" aria-label="Permalink to &quot;控件速查篇&quot;">​</a></h3><p>基类（11-16）、按钮类（17-21）、输入类（22-33）、显示类（34-37）、容器类（38-40）、列表/树/表格（41-54）、主窗口与对话框（55-74）。</p><blockquote><p>控件速查篇持续更新中，按序号推进。</p></blockquote>',13)])])}const _=d(i,[["render",o]]);export{u as __pageData,_ as default};
